import "./ResearchTicker.css";

export default function ResearchTicker() {
  return (
    <div className="research-ticker">
      <span>Research preview:</span>
      <span> Decision-making styles and personality traits</span>
      <span> • Introversion vs cognitive load</span>
      <span> • Judging vs Perceiving behavior patterns</span>
    </div>
  );
}
